pub unsafe extern "C" fn kreuzberg_ocr_config_validate(this: *const kreuzberg::OcrConfig) -> i32 {
    clear_last_error();
    if this.is_null() {
        set_last_error(1, "Null pointer passed for self");
        return -1;
    }
    // SAFETY: null check above guarantees this is a valid pointer.
    let obj = unsafe { &*this };
    let result = obj.validate();
    match result {
        Ok(()) => 0,
        Err(e) => {
            set_last_error(2, &e.to_string());
            -1
        }
    }
}

