/// Check if a given origin is allowed by CORS configuration.
///
/// Returns `true` if:
/// - CORS allows all origins (empty origins list), or
/// - The given origin is in the allowed origins list
///
/// # Arguments
///
/// * `origin` - The origin to check (e.g., "https://example.com")
///
/// # Example
///
/// ```rust
/// use kreuzberg::core::ServerConfig;
///
/// let mut config = ServerConfig::default();
/// assert!(config.is_origin_allowed("https://example.com"));
///
/// config.cors_origins.push("https://allowed.com".to_string());
/// assert!(config.is_origin_allowed("https://allowed.com"));
/// assert!(!config.is_origin_allowed("https://denied.com"));
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_server_config_is_origin_allowed(
    this: *const kreuzberg::ServerConfig,
    origin: *const std::ffi::c_char,
) -> i32 {
    clear_last_error();
    if this.is_null() {
        set_last_error(1, "Null pointer passed for self");
        return 0;
    }
    // SAFETY: null check above guarantees this is a valid pointer.
    let obj = unsafe { &*this };
    if origin.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'origin'");
        return 0;
    }
    let origin_rs = match unsafe { CStr::from_ptr(origin) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'origin'");
            return 0;
        }
    };
    let result = obj.is_origin_allowed(&origin_rs);
    if result {
        1
    } else {
        0
    }
}

