/// Create a `PdfImage` from a JSON string. Returns null on failure.
/// # Safety
/// JSON string must be valid UTF-8 and null-terminated.
/// Returned handle must be freed with `kreuzberg_pdf_image_free`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_pdf_image_from_json(json: *const c_char) -> *mut kreuzberg::pdf::PdfImage {
    clear_last_error();
    if json.is_null() {
        set_last_error(1, "Null pointer passed for JSON string");
        return std::ptr::null_mut();
    }
    let c_str = match unsafe { CStr::from_ptr(json) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in JSON string");
            return std::ptr::null_mut();
        }
    };
    match serde_json::from_str::<kreuzberg::pdf::PdfImage>(c_str) {
        Ok(val) => Box::into_raw(Box::new(val)),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

/// Serialize a `PdfImage` to a JSON string. Returns null on failure.
/// # Safety
/// `ptr` must be a valid, non-null pointer returned by a `kreuzberg` function.
/// The returned string must be freed with `kreuzberg_free_string`.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_pdf_image_to_json(ptr: *const kreuzberg::pdf::PdfImage) -> *mut c_char {
    clear_last_error();
    if ptr.is_null() {
        set_last_error(1, "Null pointer passed to to_json");
        return std::ptr::null_mut();
    }
    let val = unsafe { &*ptr };
    match serde_json::to_string(val) {
        Ok(s) => match CString::new(s) {
            Ok(cs) => cs.into_raw(),
            Err(e) => {
                set_last_error(2, &e.to_string());
                std::ptr::null_mut()
            }
        },
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

