/// Generate a deterministic cache key from configuration parameters.
///
/// # Algorithm
///
/// Uses blake3 (cryptographic, SIMD-accelerated) for collision-resistant cache keys.
/// Cache keys are generated by:
/// 1. Sorting key-value pairs by key (for determinism)
/// 2. Concatenating as "key1=val1&key2=val2&..."
/// 3. Hashing with blake3 and formatting as 32-character hex (first 128 bits)
///
/// # Example
///
/// ```rust
/// use kreuzberg::cache::generate_cache_key;
///
/// let parts = [("format", "pdf"), ("ocr", "true"), ("lang", "en")];
/// let key = generate_cache_key(&parts);
/// assert_eq!(key.len(), 32);
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_generate_cache_key(_parts: *const std::ffi::c_char) -> *mut std::ffi::c_char {
    clear_last_error();
    set_last_error(99, "Not implemented: generate_cache_key");
    std::ptr::null_mut()
}

/// Hash arbitrary bytes with blake3, returning a 32-char hex string.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_blake3_hash_bytes(data: *const u8, data_len: usize) -> *mut std::ffi::c_char {
    clear_last_error();
    if data.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'data'");
        return std::ptr::null_mut();
    }
    let data_rs = unsafe { std::slice::from_raw_parts(data, data_len) }.to_vec();
    let result = kreuzberg::cache::blake3_hash_bytes(&data_rs);
    match CString::new(result) {
        Ok(cs) => cs.into_raw(),
        Err(_) => std::ptr::null_mut(),
    }
}

/// Hash a file's content with blake3 using streaming 64 KiB reads.
///
/// Returns a 32-char hex string (128 bits of blake3 output).
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_blake3_hash_file(path: *const std::ffi::c_char) -> *mut std::ffi::c_char {
    clear_last_error();
    if path.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'path'");
        return std::ptr::null_mut();
    }
    let path_rs = match unsafe { CStr::from_ptr(path) }.to_str() {
        Ok(s) => std::path::PathBuf::from(s),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'path'");
            return std::ptr::null_mut();
        }
    };
    let result = kreuzberg::cache::blake3_hash_file(path_rs.as_path());
    match result {
        Ok(val) => match CString::new(val.to_string()) {
            Ok(cs) => cs.into_raw(),
            Err(_) => std::ptr::null_mut(),
        },
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

