///
/// ```rust
/// use kreuzberg::core::config_validation::validate_vlm_backend_config;
/// use kreuzberg::core::config::LlmConfig;
///
/// assert!(validate_vlm_backend_config("tesseract", None).is_ok());
/// let config = LlmConfig {
///     model: "openai/gpt-4o".to_string(),
///     api_key: None,
///     base_url: None,
///     timeout_secs: None,
///     max_retries: None,
///     temperature: None,
///     max_tokens: None,
/// };
/// assert!(validate_vlm_backend_config("vlm", Some(&config)).is_ok());
/// assert!(validate_vlm_backend_config("vlm", None).is_err());
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_validate_vlm_backend_config(
    backend: *const std::ffi::c_char,
    vlm_config: *const kreuzberg::LlmConfig,
) -> i32 {
    clear_last_error();
    if backend.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'backend'");
        return -1;
    }
    let backend_rs = match unsafe { CStr::from_ptr(backend) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'backend'");
            return -1;
        }
    };
    let vlm_config_rs = if vlm_config.is_null() {
        None
    } else {
        Some(unsafe { &*vlm_config }.clone())
    };
    let result = kreuzberg::core::config_validation::validate_vlm_backend_config(&backend_rs, vlm_config_rs.as_ref());
    match result {
        Ok(()) => 0,
        Err(e) => {
            set_last_error(2, &e.to_string());
            -1
        }
    }
}

/// Validate structured extraction configuration.
///
/// When structured extraction is enabled, the JSON schema must not be null or empty,
/// and the LLM config must have a non-empty model string.
///
/// # Arguments
///
/// * `schema` - The JSON schema value to validate
/// * `llm_model` - The LLM model string from the nested `LlmConfig`
///
/// # Returns
///
/// `Ok(())` if the schema is a non-empty object or array and the model is valid,
/// or a `ValidationError` if the schema is null/empty or the model is empty.
///
/// # Examples
///
/// ```rust
/// use kreuzberg::core::config_validation::validate_structured_extraction_schema;
///
/// let valid = serde_json::json!({"type": "object", "properties": {}});
/// assert!(validate_structured_extraction_schema(&valid, "openai/gpt-4o").is_ok());
///
/// let empty = serde_json::Value::Object(Default::default());
/// assert!(validate_structured_extraction_schema(&empty, "openai/gpt-4o").is_err());
///
/// let null = serde_json::Value::Null;
/// assert!(validate_structured_extraction_schema(&null, "openai/gpt-4o").is_err());
///
/// let valid = serde_json::json!({"type": "object", "properties": {}});
/// assert!(validate_structured_extraction_schema(&valid, "").is_err());
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_validate_structured_extraction_schema(
    schema: *const std::ffi::c_char,
    llm_model: *const std::ffi::c_char,
) -> i32 {
    clear_last_error();
    if schema.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'schema'");
        return -1;
    }
    let schema_str = match unsafe { CStr::from_ptr(schema) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'schema'");
            return -1;
        }
    };
    let schema_rs = match serde_json::from_str(schema_str) {
        Ok(v) => v,
        Err(_) => {
            set_last_error(1, "Invalid JSON in parameter 'schema'");
            return -1;
        }
    };
    if llm_model.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'llm_model'");
        return -1;
    }
    let llm_model_rs = match unsafe { CStr::from_ptr(llm_model) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'llm_model'");
            return -1;
        }
    };
    let result = kreuzberg::core::config_validation::validate_structured_extraction_schema(&schema_rs, &llm_model_rs);
    match result {
        Ok(()) => 0,
        Err(e) => {
            set_last_error(2, &e.to_string());
            -1
        }
    }
}

/// Extract content from a byte array.
///
/// This is the main entry point for in-memory extraction. It performs the following steps:
/// 1. Validate MIME type
/// 2. Handle legacy format conversion if needed
/// 3. Select appropriate extractor from registry
/// 4. Extract content
/// 5. Run post-processing pipeline
///
/// # Arguments
///
/// * `content` - The byte array to extract
/// * `mime_type` - MIME type of the content
/// * `config` - Extraction configuration
///
/// # Returns
///
/// An `ExtractionResult` containing the extracted content and metadata.
///
/// # Errors
///
/// Returns `KreuzbergError::Validation` if MIME type is invalid.
/// Returns `KreuzbergError::UnsupportedFormat` if MIME type is not supported.
///
/// # Example
///
/// ```rust,no_run
/// use kreuzberg::core::extractor::extract_bytes;
/// use kreuzberg::core::config::ExtractionConfig;
///
/// # async fn example() -> kreuzberg::Result<()> {
/// let config = ExtractionConfig::default();
/// let bytes = b"Hello, world!";
/// let result = extract_bytes(bytes, "text/plain", &config).await?;
/// println!("Content: {}", result.content);
/// # Ok(())
/// # }
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_extract_bytes(
    content: *const u8,
    content_len: usize,
    mime_type: *const std::ffi::c_char,
    config: *const kreuzberg::ExtractionConfig,
) -> *mut kreuzberg::ExtractionResult {
    clear_last_error();
    if content.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'content'");
        return std::ptr::null_mut();
    }
    let content_rs = unsafe { std::slice::from_raw_parts(content, content_len) }.to_vec();
    if mime_type.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'mime_type'");
        return std::ptr::null_mut();
    }
    let mime_type_rs = match unsafe { CStr::from_ptr(mime_type) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'mime_type'");
            return std::ptr::null_mut();
        }
    };
    if config.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'config'");
        return std::ptr::null_mut();
    }
    let config_rs = unsafe { &*config }.clone();
    let result =
        get_ffi_runtime().block_on(async { kreuzberg::extract_bytes(&content_rs, &mime_type_rs, &config_rs).await });
    match result {
        Ok(val) => Box::into_raw(Box::new(val.clone())),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

