/// Determine if a page's text content indicates a blank page.
///
/// A page is blank if it has fewer than [`MIN_NON_WHITESPACE_CHARS`] non-whitespace characters.
///
/// # Arguments
///
/// * `text` - The extracted text content of the page
///
/// # Returns
///
/// `true` if the page is considered blank, `false` otherwise
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_is_page_text_blank(text: *const std::ffi::c_char) -> i32 {
    clear_last_error();
    if text.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'text'");
        return 0;
    }
    let text_rs = match unsafe { CStr::from_ptr(text) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'text'");
            return 0;
        }
    };
    let result = kreuzberg::extraction::blank_detection::is_page_text_blank(&text_rs);
    if result {
        1
    } else {
        0
    }
}

