pub unsafe extern "C" fn kreuzberg_read_iwa_file(
    content: *const u8,
    content_len: usize,
    path: *const std::ffi::c_char,
) -> *mut u8 {
    clear_last_error();
    if content.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'content'");
        return std::ptr::null_mut();
    }
    let content_rs = unsafe { std::slice::from_raw_parts(content, content_len) }.to_vec();
    if path.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'path'");
        return std::ptr::null_mut();
    }
    let path_rs = match unsafe { CStr::from_ptr(path) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'path'");
            return std::ptr::null_mut();
        }
    };
    let result = kreuzberg::extractors::iwork::read_iwa_file(&content_rs, &path_rs);
    match result {
        Ok(val) => val.as_ptr() as *mut u8,
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

