///
/// This function processes multiple texts in parallel using Rayon, providing
/// significant performance improvements for batch operations. All texts use the
/// same configuration and language hint for consistency.
///
/// # Arguments
///
/// * `texts` - Slice of text references to reduce
/// * `config` - Configuration specifying reduction level and options
/// * `language_hint` - Optional ISO 639-3 language code (e.g., "eng", "spa")
///
/// # Returns
///
/// Returns a vector of reduced texts in the same order as the input.
///
/// # Errors
///
/// Returns an error if the language hint is invalid or stopwords cannot be loaded.
///
/// # Examples
///
/// ```rust
/// use kreuzberg::text::token_reduction::{batch_reduce_tokens, TokenReductionConfig, ReductionLevel};
///
/// let texts: Vec<String> = vec![
///     "This is the first document with some text.".to_string(),
///     "Here is another document with different content.".to_string(),
///     "And finally, a third document to process.".to_string(),
/// ];
/// let config = TokenReductionConfig::default();
/// let reduced = batch_reduce_tokens(&texts, &config, Some("eng"))?;
/// assert_eq!(reduced.len(), 3);
/// # Ok::<(), kreuzberg::error::KreuzbergError>(())
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_batch_reduce_tokens(
    texts: *const std::ffi::c_char,
    config: *const kreuzberg::TokenReductionConfig,
    language_hint: *const std::ffi::c_char,
) -> *mut std::ffi::c_char {
    clear_last_error();
    if texts.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'texts'");
        return std::ptr::null_mut();
    }
    let texts_rs_str = match unsafe { CStr::from_ptr(texts) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'texts'");
            return std::ptr::null_mut();
        }
    };
    let texts_rs = match serde_json::from_str::<Vec<_>>(texts_rs_str) {
        Ok(v) => v,
        Err(e) => {
            set_last_error(2, &e.to_string());
            return std::ptr::null_mut();
        }
    };
    if config.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'config'");
        return std::ptr::null_mut();
    }
    let config_rs = unsafe { &*config }.clone();
    let language_hint_rs = if language_hint.is_null() {
        None
    } else {
        match unsafe { CStr::from_ptr(language_hint) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'language_hint'");
                return std::ptr::null_mut();
            }
        }
    };
    let result = kreuzberg::text::batch_reduce_tokens(&texts_rs, &config_rs, language_hint_rs.as_deref());
    match result {
        Ok(val) => match serde_json::to_string(&val) {
            Ok(s) => match CString::new(s) {
                Ok(cs) => cs.into_raw(),
                Err(_) => std::ptr::null_mut(),
            },
            Err(_) => std::ptr::null_mut(),
        },
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

/// Calculates detailed statistics comparing original and reduced text.
///
/// Provides comprehensive metrics including reduction percentages and absolute
/// counts for both characters and tokens. Useful for analyzing the effectiveness
/// of token reduction and monitoring compression ratios.
///
/// # Arguments
///
