/// Decode raw bytes into UTF-8, using heuristics and fallback encodings when necessary.
///
/// The function prefers an explicit `encoding`, falls back to the cached guess, probes
/// an encoding detector, and finally tries a small curated list before returning a
/// mojibake-cleaned string.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_safe_decode(
    byte_data: *const u8,
    byte_data_len: usize,
    encoding: *const std::ffi::c_char,
) -> *mut std::ffi::c_char {
    clear_last_error();
    if byte_data.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'byte_data'");
        return std::ptr::null_mut();
    }
    let byte_data_rs = unsafe { std::slice::from_raw_parts(byte_data, byte_data_len) }.to_vec();
    let encoding_rs = if encoding.is_null() {
        None
    } else {
        match unsafe { CStr::from_ptr(encoding) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'encoding'");
                return std::ptr::null_mut();
            }
        }
    };
    let result = kreuzberg::utils::safe_decode(&byte_data_rs, encoding_rs.as_deref());
    match CString::new(result) {
        Ok(cs) => cs.into_raw(),
        Err(_) => std::ptr::null_mut(),
    }
}

/// Estimate how trustworthy a decoded string is on a 0.0–1.0 scale.
///
/// Scores close to 1.0 indicate mostly printable characters, whereas lower scores
/// point to mojibake, control characters, or suspicious character mixes.
