/// Convert a table grid to markdown format.
///
/// The first row is treated as the header row, with a separator line added after it.
/// Pipe characters in cell content are escaped.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_table_to_markdown(table: *const std::ffi::c_char) -> *mut std::ffi::c_char {
    clear_last_error();
    if table.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'table'");
        return std::ptr::null_mut();
    }
    let table_rs_str = match unsafe { CStr::from_ptr(table) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'table'");
            return std::ptr::null_mut();
        }
    };
    let table_rs = match serde_json::from_str::<Vec<_>>(table_rs_str) {
        Ok(v) => v,
        Err(e) => {
            set_last_error(2, &e.to_string());
            return std::ptr::null_mut();
        }
    };
    let result = kreuzberg::table_core::table_to_markdown(&table_rs);
    match CString::new(result) {
        Ok(cs) => cs.into_raw(),
        Err(_) => std::ptr::null_mut(),
    }
}

/// Load ServerConfig with proper precedence order.
///
/// This function implements the configuration hierarchy:
/// 1. File (if provided)
/// 2. Environment variables (via apply_env_overrides)
/// 3. Defaults
///
/// The config file can be in flat format (server settings at root) or nested format
/// (server settings under [server] section alongside other configs like [ocr]).
///
/// # Arguments
///
/// * `config_path` - Optional path to a ServerConfig file (TOML, YAML, or JSON)
///
/// # Returns
///
/// A configured ServerConfig with proper precedence applied.
///
/// # Errors
///
/// Returns an error if:
/// - The config file path is provided but cannot be read
/// - The config file contains invalid server configuration
/// - Environment variable overrides contain invalid values
///
/// # Examples
///
/// ```no_run
/// use kreuzberg::api::load_server_config;
///
/// # fn example() -> kreuzberg::Result<()> {
/// // Load from file with env overrides
/// let config = load_server_config(Some("server.toml"))?;
///
/// // Or use defaults with env overrides
/// let config = load_server_config(None)?;
/// # Ok(())
/// # }
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_load_server_config(
    config_path: *const std::ffi::c_char,
) -> *mut kreuzberg::ServerConfig {
    clear_last_error();
    let config_path_rs = if config_path.is_null() {
        None
    } else {
        match unsafe { CStr::from_ptr(config_path) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'config_path'");
                return std::ptr::null_mut();
            }
        }
    };
    let result = kreuzberg::api::load_server_config(config_path_rs.as_deref());
    match result {
        Ok(val) => Box::into_raw(Box::new(val.clone())),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

