/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_extract_images_from_pdf(
    pdf_bytes: *const u8,
    pdf_bytes_len: usize,
) -> *mut std::ffi::c_char {
    clear_last_error();
    if pdf_bytes.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'pdf_bytes'");
        return std::ptr::null_mut();
    }
    let pdf_bytes_rs = unsafe { std::slice::from_raw_parts(pdf_bytes, pdf_bytes_len) }.to_vec();
    let result = kreuzberg::pdf::extract_images_from_pdf(&pdf_bytes_rs);
    match result {
        Ok(val) => match serde_json::to_string(&val) {
            Ok(s) => match CString::new(s) {
                Ok(cs) => cs.into_raw(),
                Err(_) => std::ptr::null_mut(),
            },
            Err(_) => std::ptr::null_mut(),
        },
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

