/// Render a single PDF page to a PNG-encoded byte buffer.
///
/// # Errors
///
/// Returns an error if the PDF is invalid, the page index is out of bounds,
/// or if the page fails to render.
///
/// # Example
///
/// ```rust,no_run
/// use kreuzberg::pdf::render_pdf_page_to_png;
///
/// # fn example() -> kreuzberg::pdf::error::Result<()> {
/// let pdf_bytes = std::fs::read("document.pdf")?;
/// let png = render_pdf_page_to_png(&pdf_bytes, 0, Some(150), None)?;
/// std::fs::write("page_0.png", png)?;
/// # Ok(())
/// # }
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_render_pdf_page_to_png(
    pdf_bytes: *const u8,
    pdf_bytes_len: usize,
    page_index: usize,
    dpi: i32,
    password: *const std::ffi::c_char,
) -> *mut u8 {
    clear_last_error();
    if pdf_bytes.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'pdf_bytes'");
        return std::ptr::null_mut();
    }
    let pdf_bytes_rs = unsafe { std::slice::from_raw_parts(pdf_bytes, pdf_bytes_len) }.to_vec();
    let page_index_rs = page_index;
    let dpi_rs = if dpi == i32::MAX { None } else { Some(dpi) };
    let password_rs = if password.is_null() {
        None
    } else {
        match unsafe { CStr::from_ptr(password) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'password'");
                return std::ptr::null_mut();
            }
        }
    };
    let result = kreuzberg::pdf::render_pdf_page_to_png(&pdf_bytes_rs, page_index_rs, dpi_rs, password_rs.as_deref());
    match result {
        Ok(val) => val.as_ptr() as *mut u8,
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

